   141→@layer base {
   142→  * {
   143→    @apply border-border outline-ring/50;
   144→    }
   145→  body {
   146→    @apply bg-background text-foreground;
   147→    }
   148→  html {
   149→    @apply font-sans;
   150→    }
   151→}
