   153→/* ===== JukuBox.ai ランディングページ用スタイル ===== */
   154→
   155→/* フィルムグレイン質感 */
   156→body::after {
   157→  content: '';
   158→  position: fixed;
   159→  inset: 0;
   160→  background-image: url("data:image/svg+xml,<svg xmlns='http://www.w3.org/2000/svg' width='200' height='200'><filter id='n'><feTurbulence type='fractalNoise' baseFrequency='0.85' numOctaves='4' stitchTiles='stitch'/><feColorMatrix type='saturate' values='0'/></filter><rect width='200' height='200' filter='url(%23n)' opacity='0.18'/></svg>");
   161→  opacity: 0.055;
   162→  pointer-events: none;
   163→  z-index: 9000;
   164→  mix-blend-mode: overlay;
   165→}
   166→
   167→@keyframes juku-record-spin {
   168→  from { transform: rotate(0deg); }
   169→  to { transform: rotate(360deg); }
   170→}
   171→
   172→@keyframes juku-breathe {
   173→  0%, 100% { opacity: 0.85; }
   174→  50% { opacity: 1; }
   175→}
   176→
   177→@keyframes juku-glow-gold {
   178→  0%, 100% {
   179→    box-shadow: 0 0 8px var(--juku-gold-dim), 0 0 16px oklch(0.75 0.12 77 / 0.2);
   180→  }
   181→  50% {
   182→    box-shadow: 0 0 12px var(--juku-gold), 0 0 28px oklch(0.75 0.12 77 / 0.25);
   183→  }
   184→}
   185→
   186→.juku-glow-gold-text {
   187→  text-shadow: 0 0 18px oklch(0.75 0.12 77 / 0.45);
   188→}
   189→
   190→.juku-glass {
   191→  background: var(--juku-surface);
   192→  backdrop-filter: blur(20px);
   193→  -webkit-backdrop-filter: blur(20px);
   194→  border: 1px solid oklch(1 0 0 / 0.07);
   195→}
   196→
   197→.juku-grid-bg {
   198→  background-image:
   199→    linear-gradient(var(--juku-grid) 1px, transparent 1px),
   200→    linear-gradient(90deg, var(--juku-grid) 1px, transparent 1px);
   201→  background-size: 48px 48px;
   202→}
   203→
   204→.juku-record-spin {
   205→  animation: juku-record-spin 32s linear infinite;
   206→}
   207→
   208→.juku-breathe {
   209→  animation: juku-breathe 4s ease-in-out infinite;
   210→}
   211→
   212→.juku-glow-border {
   213→  animation: juku-glow-gold 4s ease-in-out infinite;
   214→}
   215→
   216→.juku-cta-btn-primary {
   217→  position: relative;
   218→  background: transparent;
   219→  border: 1px solid var(--juku-gold);
   220→  color: var(--juku-gold);
   221→  transition: all 0.35s ease;
   222→  overflow: hidden;
   223→  cursor: pointer;
   224→}
   225→
   226→.juku-cta-btn-primary::before {
   227→  content: '';
   228→  position: absolute;
   229→  inset: 0;
   230→  background: var(--juku-gold);
   231→  transform: scaleX(0);
   232→  transform-origin: left;
   233→  transition: transform 0.35s ease;
   234→  z-index: 0;
   235→}
   236→
   237→.juku-cta-btn-primary:hover::before {
   238→  transform: scaleX(1);
   239→}
   240→
   241→.juku-cta-btn-primary:hover {
   242→  color: var(--juku-bg);
   243→  box-shadow: 0 0 16px oklch(0.75 0.12 77 / 0.3);
   244→}
   245→
   246→.juku-cta-btn-primary span {
   247→  position: relative;
   248→  z-index: 1;
   249→}
   250→
   251→.juku-cta-btn-secondary {
   252→  position: relative;
   253→  background: transparent;
   254→  border: 1px solid oklch(1 0 0 / 0.2);
   255→  color: var(--juku-text-muted);
   256→  transition: all 0.3s ease;
   257→  cursor: pointer;
   258→}
   259→
   260→.juku-cta-btn-secondary:hover {
   261→  border-color: oklch(1 0 0 / 0.45);
   262→  color: var(--juku-text);
   263→}
   264→
   265→.juku-feature-card {
   266→  position: relative;
   267→  overflow: hidden;
   268→  transition: all 0.4s ease;
   269→}
   270→
   271→.juku-feature-card::before {
   272→  content: '';
   273→  position: absolute;
   274→  top: 0;
   275→  left: 0;
   276→  right: 0;
   277→  height: 1px;
   278→  background: linear-gradient(90deg, transparent, var(--juku-gold-dim), transparent);
   279→}
   280→
   281→.juku-feature-card:hover {
   282→  transform: translateY(-3px);
   283→  border-color: oklch(1 0 0 / 0.12);
   284→}
   285→
   286→.juku-divider {
   287→  width: 100%;
   288→  height: 1px;
   289→  background: linear-gradient(90deg, transparent, var(--juku-gold-dim) 30%, var(--juku-gold-dim) 70%, transparent);
   290→  opacity: 0.5;
   291→}

