function VinylRecord() {
  const grooves = Array.from({ length: 26 }, (_, i) => i);
  return (
    <svg
      viewBox="0 0 400 400"
      xmlns="http://www.w3.org/2000/svg"
      className="w-full h-full"
    >
      {/* ベース */}
      <circle cx="200" cy="200" r="195" fill="oklch(0.12 0.02 50)" />
      {/* 外縁ハイライト */}
      <circle cx="200" cy="200" r="194" fill="none" stroke="oklch(0.75 0.12 77 / 0.12)" strokeWidth="1" />
      {/* 溝 */}
      {grooves.map((i) => (
        <circle
          key={i}
          cx="200"
          cy="200"
          r={180 - i * 5}
          fill="none"
          stroke={
            i % 4 === 0
              ? "oklch(0.75 0.12 77 / 0.1)"
              : "oklch(0.75 0.12 77 / 0.03)"
          }
          strokeWidth={i % 4 === 0 ? "0.8" : "0.4"}
        />
      ))}
      {/* センターラベルエリア */}
      <circle cx="200" cy="200" r="60" fill="oklch(0.14 0.025 55)" />
      <circle cx="200" cy="200" r="57" fill="none" stroke="oklch(0.75 0.12 77 / 0.35)" strokeWidth="0.8" />
      <circle cx="200" cy="200" r="52" fill="none" stroke="oklch(0.75 0.12 77 / 0.12)" strokeWidth="0.4" />
      {/* ラベルテキスト */}
      <text
        x="200"
        y="196"
        textAnchor="middle"
        fontSize="10"
        fontFamily="Orbitron, sans-serif"
        fontWeight="700"
        fill="oklch(0.75 0.12 77)"
        letterSpacing="2.5"
      >
        JUKUBOX
      </text>
      <text
        x="200"
        y="211"
        textAnchor="middle"
        fontSize="7"

export function Nav() {
  return (
    <nav
      className="fixed top-0 left-0 right-0 z-50 flex items-center justify-between px-8 py-4"
      style={{
        background: "oklch(0.10 0.015 50 / 0.92)",
        backdropFilter: "blur(24px)",
        WebkitBackdropFilter: "blur(24px)",
        borderBottom: "1px solid oklch(0.75 0.12 77 / 0.1)",
      }}
    >
      {/* ロゴ */}
      <a href="#" className="flex items-baseline gap-0.5 no-underline">
        <span
          className="font-orbitron font-black text-xl tracking-wider juku-glow-gold-text"
          style={{ color: "var(--juku-gold)" }}
        >
          JukuBox
        </span>
        <span
          className="font-orbitron font-bold text-sm"
          style={{ color: "var(--juku-teal)" }}
        >
          .ai
        </span>
      </a>

      {/* ナビリンク */}
      <div className="hidden md:flex items-center gap-8">
        {["機能", "使い方", "学習記録"].map((label) => (
          <a
            key={label}
            href={`#${label}`}
            className="text-sm tracking-wide transition-colors duration-200"
            style={{ color: "var(--juku-text-muted)" }}
          >
            {label}
          </a>
        ))}
      </div>

      {/* CTA */}
      <button className="juku-cta-btn-primary px-5 py-2 text-xs font-orbitron font-bold uppercase tracking-widest">
        <span>無料で始める</span>
      </button>
    </nav>
  );
}

const features = [
  {
    symbol: "◈",
    title: "自分のAIで学ぶ",
    description:
      "Claude、GPT-4o、Gemini など、すでに契約しているAIエージェントをそのまま活用。追加コスト不要で最先端AIによる個別指導を実現します。",
    tag: "Bring Your Own AI",
  },
  {
    symbol: "◉",
    title: "コースを作る・使う",
    description:
      "自分でカリキュラムを組んでコースを公開。あるいはコミュニティが用意したコースをすぐに使って学習開始できます。",
    tag: "Course Library",
  },
  {
    symbol: "◎",
    title: "学習を記録する",
    description:
      "いつ・何を・どれだけ学んだかを自動記録。タイムライン形式で学習の軌跡を可視化し、継続するモチベーションを支えます。",
    tag: "Progress Tracking",
  },
  {
    symbol: "◐",
    title: "正解・不正解を分析",
    description:
      "何を理解し、何を間違えたのかを詳細に記録。弱点を把握してAIに重点的に質問できる、データドリブンな学習サイクル。",
    tag: "Mistake Analysis",
  },
];

