              {idx < steps.length - 1 && (
                <div
                  className="lg:hidden text-lg mt-1"
                  style={{ color: "var(--gold-dim)" }}
                >
                  ↓
                </div>
              )}
            </div>
          ))}
        </div>
      </div>
    </section>
  );
